example.code:
using LJCNetCommon;

// Gets the string between the specified delimiters.
private static void DelimitedString()
{
  var source = "<summary>This is some text.</summary>";
  var beginDelimiter = "<summary>";
  var endDelimiter = "</summary>";
  var textParser = new LJCTextParser();
  var result = textParser.DelimitedString(source, beginDelimiter
    , endDelimiter);
  // result:
  // This is some text.
  // StartIndex = -1;
}

using LJCNetCommon;

// Get the string including the specified delimiters.
private static void StringWithDelimiters()
{
  var line = "Value (One)";
  var beginDelimiter = "(";
  var endDelimiter = ")";
  var parser = new LJCTextParser();
  var result = parser.StringWithDelimiters(line, beginDelimiter, endDelimiter);
  // result:
  // (One)
  // StartIndex = -1;
}

// Finds the first tag in a text value.
private static void FindTag()
{
  var line = "<comment>A comment.</comment>";
  var textParser = new LJCTextParser();
  string? findTagName = null;
  var result = textParser.FindTag(line, ref findTagName);
  // result:
  // <comment>
  // findTagName = "comment"

  line = "<comment name="What?">A comment.</comment>;
  findTagName = null;
  result = textParser.FindTag(line, ref findTagName);
  // result:
  // <comment>
  // findTagName = "comment"

  findTagName = "/";
  result = textParser.FindTag(line, ref findTagName);
  // result:
  // </comment>
  // findTagName = "/comment"
}

// Removes a section from a text value.
private static void RemoveSection()
{
  var line = "<comment>A comment.</comment>";

  var textParser = new LJCTextParser();
  var beginIndex = 0;
  var endIndex = 8;
  var result = textParser.RemoveSection(line, beginIndex, endIndex);
  // result:
  // A comment.</comment>

  beginIndex = 19;
  endIndex = 28;
  result = textParser.RemoveSection(line, beginIndex, endIndex);
  // result:
  // <comment>A comment.
}

// Removes tags from a text value.
private static void RemoveTags()
{
  var line = "<comment>A comment.</comment>";

  var textParser = new LJCTextParser();
  var result = textParser.RemoveTags(line);
  // result:
  // A comment.
}
